import java.util.Random;

public class RandomGenerator {
    public static void main(String[] args) {

        Random random = new Random();

        // Generate and print 5 random integers between 1 and 100
        for (int i = 0; i < 5; i++) {
            int randomNumber = random.nextInt(100) + 1; // 1 to 100
            System.out.println(randomNumber);
        }

        // Characters for random string
        String letters = "abcdefghijklmnopqrstuvwxyz";
        String randomString = "";

        // Generate random 8-character lowercase string
        for (int i = 0; i < 8; i++) {
            int index = random.nextInt(letters.length());
            randomString += letters.charAt(index);
        }

        // Print the random string
        System.out.println(randomString);
    }
}
